package lexer

import (
	"iter"
	"unicode"
	"unicode/utf8"

	"github.com/135yshr/meow/pkg/token"
)

// Lexer tokenizes Meow source code.
type Lexer struct {
	input string
	file  string
	pos   int
	line  int
	col   int
}

// New creates a new Lexer for the given source.
func New(input, file string) *Lexer {
	return &Lexer{
		input: input,
		file:  file,
		pos:   0,
		line:  1,
		col:   1,
	}
}

func (l *Lexer) peek() rune {
	if l.pos >= len(l.input) {
		return 0
	}
	r, _ := utf8.DecodeRuneInString(l.input[l.pos:])
	return r
}

func (l *Lexer) advance() rune {
	if l.pos >= len(l.input) {
		return 0
	}
	r, size := utf8.DecodeRuneInString(l.input[l.pos:])
	l.pos += size
	if r == '\n' {
		l.line++
		l.col = 1
	} else {
		l.col++
	}
	return r
}

func (l *Lexer) peekAt(offset int) rune {
	p := l.pos + offset
	if p >= len(l.input) {
		return 0
	}
	r, _ := utf8.DecodeRuneInString(l.input[p:])
	return r
}

func (l *Lexer) makeToken(typ token.TokenType, lit string, pos token.Position) token.Token {
	return token.Token{Type: typ, Literal: lit, Pos: pos}
}

func (l *Lexer) currentPos() token.Position {
	return token.Position{File: l.file, Line: l.line, Column: l.col}
}

func (l *Lexer) skipWhitespace() {
	for l.pos < len(l.input) {
		r := l.peek()
		if r == ' ' || r == '\t' || r == '\r' {
			l.advance()
		} else {
			break
		}
	}
}

func (l *Lexer) readString() token.Token {
	pos := l.currentPos()
	l.advance() // skip opening quote
	start := l.pos
	for l.pos < len(l.input) {
		r := l.peek()
		if r == '"' {
			lit := l.input[start:l.pos]
			l.advance() // skip closing quote
			return l.makeToken(token.STRING, lit, pos)
		}
		if r == '\\' {
			l.advance() // skip backslash
		}
		l.advance()
	}
	return l.makeToken(token.ILLEGAL, l.input[start:l.pos], pos)
