  3→import (
  4→	"fmt"
  5→	"io"
  6→	"net/http"
  7→	"strings"
  8→	"time"
  9→
 10→	"github.com/135yshr/meow/runtime/meowrt"
 11→)
 12→
 13→const defaultMaxBodyBytes int64 = 1 << 20 // 1 MiB
 14→const userAgent = "meow-http-client/2.0"
 15→
 16→var client = &http.Client{
 17→	Timeout: 10 * time.Second,
 18→}
 19→
 20→type options struct {
 21→	maxBodyBytes int64
 22→	headers      map[string]string
 23→}
 24→
 25→func parseOptions(args []meowrt.Value, requiredArgs int) ([]meowrt.Value, options) {
 26→	opts := options{maxBodyBytes: defaultMaxBodyBytes}
 27→	if len(args) > requiredArgs {
 28→		if m, ok := args[len(args)-1].(*meowrt.Map); ok {
 29→			opts = extractOptions(m)
 30→			return args[:len(args)-1], opts
 31→		}
 32→	}
 33→	return args, opts
 34→}
 35→
 36→// expectString extracts a Go string from a meowrt.Value or panics with a type error.
 37→func expectString(funcName string, v meowrt.Value) string {
 38→	if v == nil {
 39→		panic(fmt.Sprintf("Hiss! %s expects a String, got <nil>, nya~", funcName))
 40→	}
 41→	s, ok := v.(*meowrt.String)
 42→	if !ok {
 43→		panic(fmt.Sprintf("Hiss! %s expects a String, got %s, nya~", funcName, v.Type()))
 44→	}
 45→	return s.Val
 46→}
 47→
 48→// readResponse reads the response body (up to limit bytes) and returns it as a meowrt.String.
 49→// It panics if the body exceeds the limit.
 50→func readResponse(resp *http.Response, limit int64) meowrt.Value {
 51→	body, err := io.ReadAll(io.LimitReader(resp.Body, limit+1))
 52→	if err != nil {
 53→		panic(fmt.Sprintf("Hiss! %s, nya~", err))
 54→	}
 55→	if int64(len(body)) > limit {
 56→		panic(fmt.Sprintf("Hiss! response body exceeds %d bytes, nya~", limit))
 57→	}
 58→	return meowrt.NewString(string(body))
 59→}
 60→
 61→// extractOptions reads option fields from a Map value.
 62→func extractOptions(m *meowrt.Map) options {
 63→	opts := options{maxBodyBytes: defaultMaxBodyBytes}
 64→	if v, found := m.Get("maxBodyBytes"); found {
 65→		if n, ok := v.(*meowrt.Int); ok {
 66→			if n.Val <= 0 {
 67→				panic(fmt.Sprintf("Hiss! maxBodyBytes must be positive, got %d, nya~", n.Val))
 68→			}
 69→			opts.maxBodyBytes = n.Val
 70→		}
 71→	}
 72→	if v, found := m.Get("headers"); found {
 73→		if hm, ok := v.(*meowrt.Map); ok {
 74→			opts.headers = make(map[string]string, len(hm.Items))
 75→			for k, val := range hm.Items {
 76→				if s, ok := val.(*meowrt.String); ok {
 77→					opts.headers[k] = s.Val
 78→				}
 79→			}
 80→		}
 81→	}
 82→	return opts
 83→}
 84→
 85→// newRequest creates an http.Request with the default User-Agent set.
 86→func newRequest(method, url string, body io.Reader) (*http.Request, error) {
 87→	req, err := http.NewRequest(method, url, body)
 88→	if err != nil {
 89→		return nil, err
 90→	}
 91→	req.Header.Set("User-Agent", userAgent)
 92→	return req, nil
 93→}
 94→
 95→// applyHeaders sets custom headers from options on the request.
 96→func applyHeaders(req *http.Request, opts options) {
 97→	for k, v := range opts.headers {
 98→		req.Header.Set(k, v)
 99→	}
100→}
101→
102→// doWithBody performs an HTTP request with a body (POST/PUT).
103→// Supported argument patterns:
104→//
105→//	(url, mapBody)       → JSON body, Content-Type: application/json
106→//	(url, strBody)       → string body, no Content-Type
107→//	(url, mapBody, opts) → JSON body, ct=application/json, headers can override
108→//	(url, strBody, opts) → string body, Content-Type via headers
109→func doWithBody(funcName, method string, args []meowrt.Value) meowrt.Value {
110→	if len(args) < 2 || len(args) > 3 {
111→		panic(fmt.Sprintf("Hiss! %s expects 2-3 arguments, got %d, nya~", funcName, len(args)))
112→	}
113→
114→	u := expectString(funcName, args[0])
115→
116→	var body string
117→	var ct string
118→	opts := options{maxBodyBytes: defaultMaxBodyBytes}
119→
120→	switch b := args[1].(type) {
121→	case *meowrt.Map:
122→		body = meowrt.ToJSON(b)
123→		ct = "application/json"
124→	case *meowrt.String:
125→		body = b.Val
126→	default:
127→		panic(fmt.Sprintf("Hiss! %s: body must be String or Map, got %s, nya~", funcName, args[1].Type()))
128→	}
129→
130→	if len(args) == 3 {
131→		optsMap, ok := args[2].(*meowrt.Map)
132→		if !ok {
133→			panic(fmt.Sprintf("Hiss! %s: 3rd argument must be Map, got %s, nya~", funcName, args[2].Type()))
134→		}
135→		opts = extractOptions(optsMap)
136→	}
137→
138→	req, err := newRequest(method, u, strings.NewReader(body))
139→	if err != nil {
140→		panic(fmt.Sprintf("Hiss! %s, nya~", err))
141→	}
142→	if ct != "" {
143→		req.Header.Set("Content-Type", ct)
144→	}
145→	applyHeaders(req, opts)
146→
147→	resp, err := client.Do(req)
148→	if err != nil {
149→		panic(fmt.Sprintf("Hiss! %s, nya~", err))
150→	}

