 68→	expected := args[1]
 69→	if actual.String() != expected.String() {
 70→		msg := fmt.Sprintf("expected %s, got %s", expected.String(), actual.String())
 71→		if len(args) >= 3 {
 72→			msg = fmt.Sprintf("%s: expected %s, got %s", args[2].String(), expected.String(), actual.String())
 73→		}
 74→		panic(testFailure{message: msg})
 75→	}
 76→	return meowrt.NewNil()
 77→}
