117→	}()
118→	return result
119→}
120→
121→// GagOr calls fn (a zero-argument Func) and recovers from any panic.
122→// If the call succeeds, its return value is returned as-is.
123→// If it panics, the fallback is used: if fallback is a Func it is called
124→// with the Furball as argument; otherwise fallback is returned directly.
125→func GagOr(fn Value, fallback Value) Value {
126→	result := Gag(fn)
127→	if _, ok := result.(*Furball); ok {
128→		if f, fok := fallback.(*Func); fok {
129→			return f.Call(result)
130→		}
131→		return fallback
132→	}
133→	return result
134→}
135→
136→// IsFurball returns NewBool(true) if v is a Furball, NewBool(false) otherwise.
137→func IsFurball(v Value) Value {
138→	_, ok := v.(*Furball)
139→	return NewBool(ok)
140→}

